export default function Login() {
  return (
    <div style={{
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      height: "70vh"
    }}>

      <div style={{
        textAlign: "center",
        background: "white",
        padding: "30px",
        borderRadius: "10px",
        boxShadow: "0 4px 10px rgba(0,0,0,0.1)"
      }}>
        <h2 style={{ fontSize: "28px", marginBottom: "20px" }}>Login</h2>

        <input placeholder="Email" style={inputStyle} />
        <br />
        <input placeholder="Password" type="password" style={inputStyle} />
        <br />

        <button style={btnBlue}>Login</button>

        <p style={{ marginTop: "10px", cursor: "pointer" }}>
          Signup
        </p>
      </div>
    </div>
  );
}

const inputStyle = {
  padding: "8px",
  margin: "5px",
  width: "200px"
};

const btnBlue = {
  background: "#2563eb",
  color: "white",
  padding: "6px 14px",
  border: "none",
  borderRadius: "5px"
};
